  add("EN-E012", "提升", "used to/be used to辨析", "结构辨析", "Yun ____ take a taxi to school, but now she is used to ____ the metro.", "小云过去常坐出租车上学，但现在习惯____地铁。", ["used to; taking", "was used to; take", "used to; take", "is used to; taking"], 0, W("前半表示过去习惯，后半表示现在已适应", "but now形成时间对比", "used to do与be used to doing组合", "两个used结构"), V("My grandfather ____ write letters by hand; now he is used to ____ messages online.", "爷爷过去常手写信，现在习惯在网上____信息。", ["used to; sending", "was used to; send", "used to; send", "is used to; sent"], 0));
